class Solution:
    def minimumSubarrayLength(self, nums, k):
        BITS = 30
        bit_count = [0] * BITS
        cur_or = 0
        left = 0
        best = float('inf')
        for right, val in enumerate(nums):
            for b in range(BITS):
                if val >> b & 1:
                    bit_count[b] += 1
                    if bit_count[b] == 1:
                        cur_or |= (1 << b)
            while left <= right and cur_or >= k:
                best = min(best, right - left + 1)
                rem = nums[left]
                for b in range(BITS):
                    if rem >> b & 1:
                        bit_count[b] -= 1
                        if bit_count[b] == 0:
                            cur_or ^= (1 << b)
                left += 1
        return best if best < float('inf') else -1

